SELECT AVG(ship_date - order_date) AS avg_shipping_time
FROM orders
WHERE ship_date IS NOT NULL;

SELECT e.employee_id, e.employee_name, e.department, e.salary,
       e.salary - AVG(e.salary) OVER (PARTITION BY e.department) AS salary_diff_from_avg
FROM employees e;

SELECT order_id, customer_id, discount
FROM orders o1
WHERE discount > (
    SELECT AVG(discount) FROM orders o2 WHERE o2.customer_id = o1.customer_id
);

SELECT SUM(discount_amount) AS total_discounts
FROM orders
WHERE discount_amount > 0;

SELECT p.product_id, p.product_name
FROM products p
WHERE NOT EXISTS (
    SELECT 1 FROM order_items oi
    WHERE oi.product_id = p.product_id AND oi.quantity <= 2
);

